   \end {tikzpicture}






      Then we unfold the restricted algebra structure.






    \usepackage {string-diagrams,preamble}


   \begin {tikzpicture}[scale=0.5,baseline=($(nw)!0.5!(se)$)]
     \path 
      coordinate (nw)
      ++(1,0) coordinate[label=above:$ I $] (n/I)
