   coordinate[dot,label=below:$ \alpha _{ I } $] (alg) at (spath cs:wire 0.4)
   coordinate[dot,label=below:$j$] (j) at (spath cs:wire 0.6)
   coordinate[label=above:$ T $] (n/T) at (nw -| alg)
 ;
